impl From<JsNodeContent> for html_to_markdown_rs::NodeContent {
    fn from(val: JsNodeContent) -> Self {
        match val.node_type_tag.as_str() {
            "heading" => Self::Heading {
                level: val.level.unwrap_or_default(),
                text: val.text.unwrap_or_default(),
            },
            "paragraph" => Self::Paragraph {
                text: val.text.unwrap_or_default(),
            },
            "list" => Self::List {
                ordered: val.ordered.unwrap_or_default(),
            },
            "listitem" => Self::ListItem {
                text: val.text.unwrap_or_default(),
            },
            "table" => Self::Table {
                grid: val.grid.unwrap_or_default().into(),
            },
            "image" => Self::Image {
                description: Some(val.description.unwrap_or_default()),
                src: Some(val.src.unwrap_or_default()),
                image_index: Some(val.image_index.unwrap_or_default()),
            },
            "code" => Self::Code {
                text: val.text.unwrap_or_default(),
                language: Some(val.language.unwrap_or_default()),
            },
            "quote" => Self::Quote,
            "definitionlist" => Self::DefinitionList,
            "definitionitem" => Self::DefinitionItem {
                term: val.term.unwrap_or_default(),
                definition: val.definition.unwrap_or_default(),
            },
            "rawblock" => Self::RawBlock {
                format: val.format.unwrap_or_default(),
                content: val.content.unwrap_or_default(),
            },
            "metadatablock" => Self::MetadataBlock {
                entries: val
                    .entries
                    .unwrap_or_default()
                    .into_iter()
                    .map(|s| {
                        let mut parts = s.splitn(2, '\t');
                        let key = parts.next().unwrap_or("").to_string();
                        let value = parts.next().unwrap_or("").to_string();
                        (key, value)
                    })
                    .collect(),
            },
            "group" => Self::Group {
                label: Some(val.label.unwrap_or_default()),
                heading_level: Some(val.heading_level.unwrap_or_default()),
                heading_text: Some(val.heading_text.unwrap_or_default()),
            },
            _ => Self::Heading {
                level: Default::default(),
                text: Default::default(),
            },
        }
    }
}

